{
  "name": "Lumina: Early Awareness",
  "description": "An AI-driven experience for educators to quietly notice early learning drift through patterns and gentle observations, prioritizing student dignity and calm support."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Observation {
  id: string;
  type: 'participation' | 'tempo' | 'focus';
  description: string;
  intensity: 'subtle' | 'moderate';
}

export interface EngagementData {
  time: string;
  consistency: number;
  depth: number;
}

export interface AIPerspective {
  observation: string;
  rationale: string;
  suggestions: string[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { AIPerspective } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getObservationalInsight(data: any): Promise<AIPerspective> {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Analyze these subtle behavioral patterns for a learner and provide a calm, non-judgmental observation.
    Pattern Data: ${JSON.stringify(data)}

    Guidelines:
    1. Do NOT use labels like "at risk", "failing", or "disengaged".
    2. Use terms like "drift", "tempo change", or "shifting focus".
    3. The tone must be neutral, observant, and supportive.
    4. Focus on curiosity rather than diagnosis.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          observation: { type: Type.STRING, description: "A high-level, calm observation of the pattern." },
          rationale: { type: Type.STRING, description: "Why this observation was noted, focused on behavior." },
          suggestions: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "Gentle, optional actions that respect student autonomy."
          }
        },
        required: ["observation", "rationale", "suggestions"]
      }
    }
  });

  return JSON.parse(response.text.trim());
}

import React, { useState, useEffect, useCallback } from 'react';
import { AwarenessEntry } from './components/Sections/AwarenessEntry';
import { EngagementPatterns } from './components/Sections/EngagementPatterns';
import { DriftIndicators } from './components/Sections/DriftIndicators';
import { MomentSupport } from './components/Sections/MomentSupport';
import { NextSteps } from './components/Sections/NextSteps';
import { getObservationalInsight } from './services/geminiService';
import { AIPerspective } from './types';

const App: React.FC = () => {
  const [currentSection, setCurrentSection] = useState(0);
  const [insight, setInsight] = useState<AIPerspective | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const totalSections = 5;

  const nextSection = () => {
    if (currentSection < totalSections - 1) {
      setCurrentSection(prev => prev + 1);
    }
  };

  const prevSection = () => {
    if (currentSection > 0) {
      setCurrentSection(prev => prev - 1);
    }
  };

  const fetchInsight = useCallback(async () => {
    setIsLoading(true);
    try {
      const mockData = {
        consistency: [0.9, 0.85, 0.82, 0.75, 0.72],
        responseTempo: "Gradual increase in pause duration over 4 days",
        interactionType: "Shift from collaborative to solitary review"
      };
      const result = await getObservationalInsight(mockData);
      setInsight(result);
    } catch (error) {
      console.error("Failed to fetch AI perspective:", error);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchInsight();
  }, [fetchInsight]);

  const sections = [
    <AwarenessEntry onNext={nextSection} />,
    <EngagementPatterns onNext={nextSection} onPrev={prevSection} />,
    <DriftIndicators onNext={nextSection} onPrev={prevSection} />,
    <MomentSupport 
      onNext={nextSection} 
      onPrev={prevSection} 
      insight={insight} 
      isLoading={isLoading} 
    />,
    <NextSteps onPrev={prevSection} />
  ];

  return (
    <div className="relative h-screen w-full overflow-hidden bg-stone-50">
      {/* Progress Indicator */}
      <div className="fixed top-8 left-1/2 -translate-x-1/2 flex gap-3 z-50">
        {Array.from({ length: totalSections }).map((_, i) => (
          <div 
            key={i}
            className={`h-1.5 rounded-full transition-all duration-500 ${
              i === currentSection ? 'w-8 bg-stone-600' : 'w-2 bg-stone-200'
            }`}
          />
        ))}
      </div>

      <div 
        className="section-transition h-full w-full"
        style={{ transform: `translateY(-${currentSection * 100}%)` }}
      >
        {sections.map((Section, index) => (
          <div key={index} className="h-full w-full flex-shrink-0">
            {Section}
          </div>
        ))}
      </div>

      {/* Floating Brand Label */}
      <div className="fixed bottom-8 left-8 text-stone-400 text-xs font-medium tracking-widest uppercase pointer-events-none">
        Lumina / Sensing Layer
      </div>
    </div>
  );
};

export default App;

