import { EngagementPoint } from '../types';

export const generateSyntheticData = (): EngagementPoint[] => {
  const days = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];
  return days.map(day => ({
    time: day,
    consistency: 60 + Math.random() * 40,
    depth: 40 + Math.random() * 50,
    focus: 50 + Math.random() * 50,
  }));
};

import React, { useState, useEffect } from 'react';

export const RealTimeClock: React.FC = () => {
  const [time, setTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  return (
    <div className="mono text-[10px] tracking-[0.2em] text-stone-500 flex items-center gap-4">
      <div className="flex flex-col items-end">
        <span className="text-stone-300">{time.toLocaleTimeString([], { hour12: false })}</span>
        <span className="opacity-50 uppercase">{time.toLocaleDateString([], { month: 'short', day: 'numeric', year: 'numeric' })}</span>
      </div>
      <div className="h-8 w-[1px] bg-stone-800" />
