import { GoogleGenAI, Type } from "@google/genai";
import { AIPerspective } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getObservationalInsight(data: any): Promise<AIPerspective> {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Analyze these subtle behavioral patterns for a learner and provide a calm, non-judgmental observation.
    Pattern Data: ${JSON.stringify(data)}

    Guidelines:
    1. Do NOT use labels like "at risk" or "failing".
    2. Focus on "drift" and "rhythm".
    3. Determine if the student is currently "Actively Studying" (high consistency/depth) or showing "Potential Drift".
    4. Provide an overall engagement score (0-100).

    The tone must be clinical yet supportive.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          observation: { type: Type.STRING },
          rationale: { type: Type.STRING },
          suggestions: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          },
          isStudying: { type: Type.BOOLEAN, description: "True if patterns suggest active engagement, False if drifting." },
          engagementScore: { type: Type.NUMBER, description: "0 to 100 based on the provided data." }
        },
        required: ["observation", "rationale", "suggestions", "isStudying", "engagementScore"]
      }
    }
  });

  return JSON.parse(response.text.trim());
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { AwarenessEntry } from './components/Sections/AwarenessEntry';
import { EngagementPatterns } from './components/Sections/EngagementPatterns';
import { DriftIndicators } from './components/Sections/DriftIndicators';
import { MomentSupport } from './components/Sections/MomentSupport';
import { NextSteps } from './components/Sections/NextSteps';
import { RealTimeClock } from './components/RealTimeClock';
import { getObservationalInsight } from './services/geminiService';
import { generateSyntheticData } from './utils/dataGenerator';
import { AIPerspective, EngagementPoint } from './types';

const STORAGE_KEY_DATA = 'lumina_synthetic_data';
const STORAGE_KEY_INSIGHT = 'lumina_insight';

const App: React.FC = () => {
  const [currentSection, setCurrentSection] = useState(0);
  const [insight, setInsight] = useState<AIPerspective | null>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_INSIGHT);
    return saved ? JSON.parse(saved) : null;
  });
  const [syntheticData, setSyntheticData] = useState<EngagementPoint[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_DATA);
    return saved ? JSON.parse(saved) : [];
  });
  const [isLoading, setIsLoading] = useState(false);
  const isScrolling = useRef(false);

  const totalSections = 5;

  const handleScroll = useCallback((e: WheelEvent) => {
    if (isScrolling.current) return;

    if (e.deltaY > 50 && currentSection < totalSections - 1) {
      isScrolling.current = true;
      setCurrentSection(prev => prev + 1);
      setTimeout(() => isScrolling.current = false, 1200);
    } else if (e.deltaY < -50 && currentSection > 0) {
      isScrolling.current = true;
      setCurrentSection(prev => prev - 1);
      setTimeout(() => isScrolling.current = false, 1200);
    }
  }, [currentSection]);

  useEffect(() => {
    window.addEventListener('wheel', handleScroll);
    return () => window.removeEventListener('wheel', handleScroll);
  }, [handleScroll]);

  const initSession = useCallback(async () => {
    // If we already have data and insight from local storage, don't re-generate
    if (syntheticData.length > 0 && insight) {
      return;
    }

    setIsLoading(true);
    const data = syntheticData.length > 0 ? syntheticData : generateSyntheticData();
    if (syntheticData.length === 0) {
      setSyntheticData(data);
      localStorage.setItem(STORAGE_KEY_DATA, JSON.stringify(data));
    }

    try {
      // If we have data but no insight (e.g. previous fetch failed), fetch it
      if (!insight) {
        const result = await getObservationalInsight(data);
        setInsight(result);
        localStorage.setItem(STORAGE_KEY_INSIGHT, JSON.stringify(result));
      }
    } catch (error) {
      console.error("AI Insight error:", error);
    } finally {
      setIsLoading(false);
    }
  }, [syntheticData, insight]);

  useEffect(() => {
    initSession();
  }, [initSession]);

  const sections = [
    <AwarenessEntry />,
    <EngagementPatterns data={syntheticData} />,
    <DriftIndicators />,
    <MomentSupport insight={insight} isLoading={isLoading} />,
    <NextSteps />
  ];

  return (
    <div className="relative h-screen w-full overflow-hidden bg-[#0c0a09]">
      {/* Header Overlay */}
      <header className="fixed top-0 left-0 w-full p-8 flex justify-between items-start z-[100] pointer-events-none">
        <div className="mono text-[10px] tracking-[0.3em] font-light flex items-center gap-3 pointer-events-auto">
          <div className="w-8 h-[1px] bg-amber-500/50" />
          <span className="text-stone-100 uppercase font-semibold">Lumina</span>
          <span className="text-stone-500">SENSING LAYER v2.1</span>
        </div>
        <div className="pointer-events-auto">
          <RealTimeClock />
        </div>
      </header>

      {/* Vertical Progress Dots */}
      <div className="fixed right-8 top-1/2 -translate-y-1/2 flex flex-col gap-6 z-50">
        {Array.from({ length: totalSections }).map((_, i) => (
          <div key={i} className="group flex items-center gap-4 cursor-pointer" onClick={() => setCurrentSection(i)}>
            <div className={`mono text-[9px] transition-all duration-500 ${i === currentSection ? 'opacity-100 text-amber-500' : 'opacity-0'}`}>
              0{i + 1}
            </div>
            <div className={`h-[2px] transition-all duration-500 ${i === currentSection ? 'w-8 bg-amber-500' : 'w-2 bg-stone-700 group-hover:bg-stone-500'}`} />
          </div>
        ))}
      </div>

      {/* Main Container */}
      <div 
        className="section-transition h-full w-full"
        style={{ transform: `translateY(-${currentSection * 100}%)` }}
      >
        {sections.map((Section, index) => (
          <div key={index} className="h-screen w-full flex-shrink-0 flex items-center justify-center relative">
             <div className="absolute inset-0 bg-[radial-gradient(circle_at_50%_50%,rgba(120,113,108,0.03)_0%,transparent_70%)] pointer-events-none" />
             {Section}
          </div>
        ))}
      </div>

      {/* Footer Meta */}
      <footer className="fixed bottom-8 left-8 flex items-center gap-12 z-50 pointer-events-none">
        <div className="mono text-[9px] tracking-[0.2em] text-stone-600">
           GRID_COORD: 37.77 / -122.41
        </div>
        <div className="mono text-[9px] tracking-[0.2em] text-stone-600">
           PROTO: SECURE_DATA_LAYER
        </div>
      </footer>

      {/* Scroll Indicator */}
      <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-50 pointer-events-none opacity-40">
        <div className="flex flex-col items-center gap-2">
           <div className="w-[1px] h-12 bg-gradient-to-b from-stone-800 to-amber-500/50" />
           <span className="mono text-[8px] tracking-widest uppercase text-stone-500">Scroll to Explore</span>
        </div>
      </div>
    </div>
  );
};

