import React, { useState, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { AIPerspective } from '../types';

interface Props {
  insight: AIPerspective | null;
}

export const VideoVisualizationTile: React.FC<Props> = ({ insight }) => {
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [loadingStep, setLoadingStep] = useState(0);
  const [hasApiKey, setHasApiKey] = useState(false);

  const loadingMessages = [
    "Reading focus rhythms...",
    "Understanding cognitive breath...",
    "Composing serenity...",
    "Synthesizing visual calm...",
    "Almost ready for you..."
  ];

  useEffect(() => {
    // Check for API key presence
    const checkKey = async () => {
      // @ts-ignore - window.aistudio is injected
      const selected = await window.aistudio?.hasSelectedApiKey();
      setHasApiKey(!!selected);
    };
    checkKey();
  }, []);

  const handleOpenKeySelector = async () => {
    // @ts-ignore
    await window.aistudio?.openSelectKey();
    setHasApiKey(true); // Proceed assuming success per instructions
  };

  const generateVideo = async () => {
    if (!insight) return;
    setIsGenerating(true);
    setLoadingStep(0);

    const stepInterval = setInterval(() => {
      setLoadingStep(prev => (prev + 1) % loadingMessages.length);
    }, 4000);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // Construct a prompt for mental health understanding based on insight
      const basePrompt = insight.isStudying 
        ? "A peaceful cinematic video of soft golden light illuminating a quiet, ancient library filled with books. Floating dust motes move slowly in the sunbeams. Calm, steady, 4k, serene atmosphere."
        : "A gentle abstract visualization of calm ocean waves turning into soft, flowing watercolor clouds. A transition from chaos to pure white tranquility. Cinematic, 4k, restorative mood.";

      let operation = await ai.models.generateVideos({
        model: 'veo-3.1-fast-generate-preview',
        prompt: basePrompt,
        config: {
          numberOfVideos: 1,
          resolution: '720p',
          aspectRatio: '16:9'
        }
      });

      while (!operation.done) {
        await new Promise(resolve => setTimeout(resolve, 10000));
        operation = await ai.operations.getVideosOperation({ operation: operation });
      }

      const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
      if (downloadLink) {
        const fetchUrl = `${downloadLink}&key=${process.env.API_KEY}`;
        const response = await fetch(fetchUrl);
        const blob = await response.blob();
        setVideoUrl(URL.createObjectURL(blob));
      }
    } catch (error: any) {
      console.error("Video Generation Error:", error);
      if (error?.message?.includes("entity was not found")) {
        setHasApiKey(false);
        alert("Please re-select your API key to continue.");
      }
    } finally {
      clearInterval(stepInterval);
      setIsGenerating(false);
    }
  };

  return (
    <div className="tile lg:col-span-5 p-6 flex flex-col h-[500px] relative overflow-hidden group">
      <div className="tile-header">
        <span>Mental Health Visualization</span>
        <span className="mono text-[8px] opacity-40">Veo v3.1 Sensing</span>
      </div>

      <div className="flex-1 flex flex-col items-center justify-center relative bg-black/40 rounded border border-stone-800/40 overflow-hidden">
        {!hasApiKey ? (
          <div className="text-center p-8 space-y-6">
            <div className="w-12 h-12 rounded-full border border-amber-900/30 flex items-center justify-center mx-auto mb-4">
              <svg className="w-6 h-6 text-amber-500/50" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" /></svg>
            </div>
            <p className="text-stone-400 text-sm italic font-light">Visualizing mental health patterns requires a secure intelligence layer.</p>
            <button 
              onClick={handleOpenKeySelector}
              className="px-6 py-2 bg-amber-600/10 border border-amber-600/30 text-amber-500 mono text-[10px] tracking-widest hover:bg-amber-600/20 transition-all uppercase"
            >
              Unlock Visualization
            </button>
            <div className="text-[8px] text-stone-600 mt-2">
              Requires a project with billing enabled. <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" className="underline">View Docs</a>
            </div>
          </div>
        ) : isGenerating ? (
          <div className="text-center space-y-6 animate-pulse">
            <div className="relative w-16 h-16 mx-auto">
               <div className="absolute inset-0 border-2 border-amber-500/20 rounded-full"></div>
               <div className="absolute inset-0 border-2 border-amber-500 border-t-transparent rounded-full animate-spin"></div>
            </div>
            <div className="space-y-2">
              <p className="text-stone-300 font-light italic">{loadingMessages[loadingStep]}</p>
              <p className="text-stone-600 mono text-[9px] uppercase tracking-tighter">Veo 3: Synthesizing Latent Space</p>
            </div>
          </div>
        ) : videoUrl ? (
          <div className="w-full h-full relative group/video">
            <video 
              src={videoUrl} 
              autoPlay 
              loop 
              muted 
              className="w-full h-full object-cover"
            />
            <div className="absolute inset-0 bg-black/40 opacity-0 group-hover/video:opacity-100 transition-opacity flex items-center justify-center">
               <button 
                onClick={generateVideo}
                className="px-4 py-2 bg-white/10 backdrop-blur-md border border-white/20 text-white mono text-[10px] tracking-widest uppercase hover:bg-white/20"
               >
                 Regenerate Flow
               </button>
            </div>
          </div>
        ) : (
          <div className="text-center p-8 space-y-4">
             <div className="text-4xl font-extralight text-stone-700 tracking-tighter mb-4">RESTORE FOCUS</div>
             <p className="text-stone-500 text-xs font-light max-w-xs mx-auto mb-6">
               Generate a personalized cinematic visualization of your current mental posture to aid in grounding and reflection.
             </p>
             <button 
              onClick={generateVideo}
              disabled={!insight}
              className="px-8 py-3 bg-stone-100 text-stone-900 font-medium text-xs tracking-widest hover:bg-white transition-all uppercase disabled:opacity-20"
             >
               Generate Calm
             </button>
          </div>
        )}
      </div>

      <div className="mt-4 flex items-center justify-between text-[8px] mono text-stone-600 tracking-widest">
        <span>MODE: CINEMATIC_GROUNDING</span>
        <span>RESOLUTION: 720P_OPTIMIZED</span>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { RealTimeClock } from './components/RealTimeClock';
import { getObservationalInsight } from './services/geminiService';
import { generateSyntheticData } from './utils/dataGenerator';
import { AIPerspective, EngagementPoint } from './types';
import { VideoVisualizationTile } from './components/VideoVisualizationTile';
import { EngagementPatterns } from './components/Sections/EngagementPatterns';
import { DriftIndicators } from './components/Sections/DriftIndicators';
import { MomentSupport } from './components/Sections/MomentSupport';
import { NextSteps } from './components/Sections/NextSteps';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer 
} from 'recharts';

const STORAGE_KEY_DATA = 'lumina_synthetic_data';
const STORAGE_KEY_INSIGHT = 'lumina_insight';

type ViewType = 'dashboard' | 'insights' | 'intelligence' | 'actions';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewType>('dashboard');
  const [insight, setInsight] = useState<AIPerspective | null>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_INSIGHT);
    return saved ? JSON.parse(saved) : null;
  });
  const [syntheticData, setSyntheticData] = useState<EngagementPoint[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_DATA);
    return saved ? JSON.parse(saved) : [];
  });
  const [isLoading, setIsLoading] = useState(false);

  const initSession = useCallback(async () => {
    if (syntheticData.length > 0 && insight) return;
    setIsLoading(true);
    const data = syntheticData.length > 0 ? syntheticData : generateSyntheticData();
    if (syntheticData.length === 0) {
      setSyntheticData(data);
      localStorage.setItem(STORAGE_KEY_DATA, JSON.stringify(data));
    }
    try {
      if (!insight) {
        const result = await getObservationalInsight(data);
        setInsight(result);
        localStorage.setItem(STORAGE_KEY_INSIGHT, JSON.stringify(result));
      }
    } catch (error) {
      console.error("AI Insight error:", error);
    } finally {
      setIsLoading(false);
    }
  }, [syntheticData, insight]);

  useEffect(() => {
    initSession();
  }, [initSession]);

  const navItems: { label: string; id: ViewType }[] = [
    { label: 'Dashboard', id: 'dashboard' },
    { label: 'Insights', id: 'insights' },
    { label: 'Intelligence', id: 'intelligence' },
    { label: 'Actions', id: 'actions' },
  ];

  const handleNextView = () => {
    const currentIndex = navItems.findIndex(item => item.id === currentView);
    if (currentIndex < navItems.length - 1) {
      setCurrentView(navItems[currentIndex + 1].id);
    } else {
      setCurrentView('dashboard');
    }
  };

  const renderViewContent = () => {
    switch (currentView) {
      case 'insights':
        return (
          <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <EngagementPatterns data={syntheticData} />
            <DriftIndicators />
          </div>
        );
      case 'intelligence':
        return (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
              <div className="lg:col-span-12">
                <MomentSupport insight={insight} isLoading={isLoading} />
              </div>
              <div className="lg:col-span-12 flex justify-center">
                <div className="w-full max-w-4xl">
                  <VideoVisualizationTile insight={insight} />
                </div>
              </div>
            </div>
          </div>
        );
      case 'actions':
        return (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-700">
            <NextSteps />
          </div>
        );
      case 'dashboard':
      default:
        return (
          <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-6 animate-in fade-in duration-700">
            {/* Weekly Records Tile */}
            <div className="tile lg:col-span-4 p-6 flex flex-col h-[500px]">
              <div className="tile-header">
                <span>Engagement Flow</span>
                <span className="text-amber-500">{insight?.engagementScore || '--'}% Quality</span>
              </div>
              <div className="flex-1 overflow-hidden">
                <div className="text-3xl font-light text-stone-200 mb-6 tracking-tight">Focus Rhythm</div>
                <div className="h-[200px] w-full">
                  <ResponsiveContainer width="100%" height="100%">
                    <AreaChart data={syntheticData}>
                      <defs>
                        <linearGradient id="colorCons" x1="0" y1="0" x2="0" y2="1">
                          <stop offset="5%" stopColor="#d97706" stopOpacity={0.2}/>
                          <stop offset="95%" stopColor="#d97706" stopOpacity={0}/>
                        </linearGradient>
                      </defs>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#292524" />
                      <XAxis dataKey="time" axisLine={false} tickLine={false} tick={{fill: '#57534e', fontSize: 10}} />
                      <YAxis hide />
                      <Area type="monotone" dataKey="consistency" stroke="#d97706" fillOpacity={1} fill="url(#colorCons)" strokeWidth={1} />
                    </AreaChart>
                  </ResponsiveContainer>
                </div>
                <div className="mt-6 space-y-4">
                  {['Focus', 'Resilience', 'Presence'].map((sub, i) => (
                    <div key={sub} className="flex items-center gap-3">
                      <span className="text-[10px] mono text-stone-400 w-24">{sub}</span>
                      <div className="flex-1 h-[2px] bg-stone-800 rounded-full overflow-hidden">
                        <div className="h-full bg-stone-600" style={{width: `${75 - (i*12)}%`, backgroundColor: i === 0 ? '#d97706' : '#57534e'}}></div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            {/* Video Visualization Tile */}
            <VideoVisualizationTile insight={insight} />

            {/* Drifts & Markers */}
            <div className="tile lg:col-span-3 p-6 h-[500px]">
              <div className="tile-header">
                <span>Markers</span>
                <button onClick={() => setCurrentView('insights')} className="hover:text-amber-500 transition-colors">Details &gt;</button>
              </div>
              <div className="text-xl font-light mb-8 italic text-stone-300">Quiet Observations</div>
              <div className="space-y-4">
                <div className="p-4 bg-stone-900/40 border border-stone-800/50 rounded flex justify-between items-start">
                  <div>
                    <div className="text-xs text-stone-100 font-medium mb-1">Attention Drift</div>
                    <div className="text-[10px] text-stone-500 mono uppercase tracking-tighter">Latent response detected</div>
                  </div>
                </div>
                <div className="p-4 bg-stone-900/40 border border-stone-800/50 rounded flex justify-between items-start opacity-70">
                  <div>
                    <div className="text-xs text-stone-300 font-medium mb-1">Cognitive Pace</div>
                    <div className="text-[10px] text-stone-600 mono uppercase tracking-tighter">Consistency nominal</div>
                  </div>
                </div>
              </div>
            </div>

            <div className="tile lg:col-span-12 p-8 relative overflow-hidden">
              <div className="flex items-center justify-between">
                <div className="space-y-1">
                  <div className="text-[10px] mono text-amber-500/70 uppercase tracking-widest">Global Status</div>
                  <div className="text-xl font-light text-stone-100 italic">"{insight?.observation || 'Scanning patterns...'}"</div>
                </div>
                <button 
                  onClick={() => setCurrentView('intelligence')}
                  className="px-6 py-2 bg-stone-800 border border-stone-700 text-stone-300 mono text-[10px] tracking-widest hover:bg-stone-700 transition-all uppercase"
                >
                  Enter Intelligence Layer
                </button>
              </div>
            </div>
          </div>
        );
    }
  };

  return (
    <div className="dashboard-overlay min-h-screen p-6 md:p-12 overflow-y-auto relative">
      {/* Top Navigation Bar */}
      <nav className="flex justify-between items-center mb-16 border-b border-stone-800/50 pb-4 sticky top-0 bg-stone-950/20 backdrop-blur-xl z-[100]">
        <div className="flex gap-4 md:gap-8 mono text-[10px] tracking-widest uppercase">
          {navItems.map((item) => (
            <button
              key={item.id}
              onClick={() => setCurrentView(item.id)}
              className={`transition-all duration-300 pb-1 ${
                currentView === item.id 
                  ? 'text-amber-500 font-bold border-b-2 border-amber-500' 
                  : 'text-stone-500 hover:text-stone-300'
              }`}
            >
              {item.label}
            </button>
          ))}
        </div>
        <div className="flex items-center gap-6">
          <div className="text-stone-500 hover:text-stone-300 cursor-pointer hidden md:block">
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          </div>
          <div className="w-8 h-8 rounded-full bg-stone-800 border border-stone-700 flex items-center justify-center overflow-hidden">
             <img src="https://ui-avatars.com/api/?name=Lumina+User&background=292524&color=78716c" alt="Profile" />
          </div>
        </div>
      </nav>

      {/* Hero Header */}
      <div className="text-center mb-16 space-y-4">
        <h1 className="serif text-5xl md:text-7xl text-stone-100 tracking-tight font-light uppercase">
          {navItems.find(i => i.id === currentView)?.label}
        </h1>
        <p className="text-stone-500 mono text-xs tracking-[0.4em] uppercase">Understanding patterns of engagement & mental health</p>
      </div>

      {/* View Content */}
      <main className="pb-24">
        {renderViewContent()}
      </main>

      {/* Floating System Info & Navigation */}
      <div className="fixed bottom-6 right-6 flex items-center gap-4 z-[100]">
        <button 
          onClick={handleNextView}
          className="group flex items-center gap-3 bg-amber-600 text-stone-950 px-6 py-3 rounded-full font-bold text-xs tracking-widest uppercase shadow-2xl hover:bg-amber-500 transition-all active:scale-95 pointer-events-auto"
        >
          Next Phase
          <svg className="w-4 h-4 group-hover:translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M14 5l7 7m0 0l-7 7m7-7H3" />
          </svg>
        </button>
        <div className="pointer-events-none hidden sm:block">
          <RealTimeClock />
        </div>
      </div>

      <style>{`
        @keyframes loading { 0% { transform: translateX(-100%); } 100% { transform: translateX(100%); } }
        .animate-in {
          animation: fadeIn 0.8s ease-out forwards;
        }
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(10px); }
          to { opacity: 1; transform: translateY(0); }
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
