  onSave: (remarks: string) => void;
}

export const TeacherPortal: React.FC<Props> = ({ remarks, onSave }) => {
  const [currentRemarks, setCurrentRemarks] = useState(remarks);

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      <div className="tile p-12">
        <div className="tile-header mb-8">
          <span>Official Educator Observation Log</span>
          <span>Security Protocol: Alpha</span>
        </div>

        <div className="space-y-6">
          <label className="block mono text-[10px] text-amber-500 uppercase tracking-widest">Qualitative Findings</label>
