            <div className="text-[9px] mono text-stone-600 uppercase">Last updated: {new Date().toLocaleTimeString()}</div>
            <button 
              onClick={() => onSave(currentRemarks)}
              className="px-8 py-3 bg-amber-600 text-stone-950 font-bold text-xs tracking-widest uppercase hover:bg-amber-500 transition-all rounded"
            >
              Commit to Intelligence Layer
            </button>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="tile p-6 border-l-2 border-l-stone-600">
           <h4 className="mono text-[9px] text-stone-500 uppercase mb-2">Pedagogical Context</h4>
