           <h4 className="mono text-[9px] text-stone-500 uppercase mb-2">Privacy Assurance</h4>
           <p className="text-xs text-stone-400 font-light">Remarks are visible to authorized parents and designated learning coaches only.</p>
        </div>
      </div>
    </div>
  );
};

