            <div className="tile rgb-border lg:col-span-12 p-8 relative overflow-hidden">
              <div className="flex flex-col md:flex-row items-center justify-between gap-6">
                <div className="space-y-1 text-center md:text-left">
                  <div className="text-[10px] mono text-cyan-400 uppercase tracking-widest">Sensing Profile: {activeStudent.name}</div>
                  <div className="text-2xl font-light text-stone-100 italic">"{activeStudent.insight?.observation || 'Synthesizing patterns...'}"</div>
                </div>
                <div className="flex flex-wrap justify-center gap-4">
                  {userRole === 'teacher' && (
                    <button onClick={() => setCurrentView('teacher')} className="px-6 py-2 bg-stone-950 border border-magenta-500/30 text-magenta-400 mono text-[10px] tracking-widest hover:bg-magenta-900/20 transition-all uppercase rounded-full glow-red">Manage Log</button>
                  )}
                  {userRole === 'parent' && (
                    <button onClick={() => setCurrentView('parent')} className="px-6 py-2 bg-stone-950 border border-cyan-500/30 text-cyan-400 mono text-[10px] tracking-widest hover:bg-cyan-900/20 transition-all uppercase rounded-full glow-blue">Full Report</button>
