               {students.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
             </select>
          )}

          <div className="flex bg-stone-950 border border-white/10 rounded-full p-1 shadow-inner">
            {(['student', 'teacher', 'parent'] as UserRole[]).map(role => (
              <button
                key={role}
                onClick={() => handleRoleChange(role)}
                className={`px-4 py-1.5 text-[8px] mono rounded-full transition-all uppercase ${userRole === role ? 'bg-white text-stone-950 font-bold' : 'text-stone-600 hover:text-stone-300'}`}
              >
                {role}
              </button>
            ))}
          </div>
        </div>
      </nav>

      {/* Hero Header */}
      <div className="text-center mb-20 space-y-6">
        <h1 className="serif text-6xl md:text-8xl text-stone-50 tracking-tighter font-light uppercase">
          {activeStudent.name}
