          </div>
          <div className="space-y-6">
             <div className="flex gap-2">
                <input 
                  type="text" 
                  value={newStudentName}
                  onChange={(e) => setNewStudentName(e.target.value)}
                  placeholder="Full Name..."
                  className="flex-1 bg-stone-900 border border-white/5 rounded-lg px-4 py-3 text-[11px] mono text-stone-300 outline-none focus:border-cyan-500/50"
                />
