                  onClick={handleAdd}
                  className="bg-cyan-600 hover:bg-cyan-500 text-stone-950 px-4 py-2 rounded-lg font-bold text-[10px] uppercase transition-colors"
                >
                  Add
                </button>
             </div>
             <div className="h-[350px] overflow-y-auto space-y-3 pr-2 scrollbar-thin">
                {students.map(s => (
                  <button
                    key={s.id}
