                    className={`w-full text-left px-5 py-4 rounded-xl border transition-all relative overflow-hidden group ${s.id === student.id ? 'bg-cyan-900/20 border-cyan-500/40 text-cyan-400 shadow-[0_0_15px_rgba(6,182,212,0.1)]' : 'bg-stone-900/40 border-white/5 text-stone-500 hover:border-white/20'}`}
                  >
                    <div className="text-[11px] mono font-bold uppercase tracking-wider">{s.name}</div>
