        </div>

        {/* Detailed Input Form */}
        <div className="md:col-span-8 tile rgb-border p-12 glow-red bg-stone-950/40">
          <div className="tile-header mb-10">
            <span className="rgb-text font-bold uppercase tracking-[0.2em]">Profile Configuration</span>
