          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-10">
             <div className="space-y-3">
               <label className="mono text-[9px] text-stone-500 uppercase tracking-widest">Full Name</label>
               <input 
                 type="text" 
