               />
             </div>
             <div className="space-y-3">
               <label className="mono text-[9px] text-stone-500 uppercase tracking-widest">Current Grade</label>
               <input 
                 type="text" 
                 value={formData.grade}
                 onChange={(e) => setFormData({...formData, grade: e.target.value})}
                 className="w-full bg-stone-900/60 border border-white/5 rounded-xl px-5 py-3 text-stone-200 mono text-xs focus:outline-none focus:border-magenta-500/30"
               />
             </div>
