              Sync & Commit Profile
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip as RechartsTooltip } from 'recharts';
import { Student } from '../../types';

interface Props {
  student: Student;
}

export const ParentPortal: React.FC<Props> = ({ student }) => {
  const { name, age, grade, focusArea, remarks, engagementData, insight } = student;

  const avgConsistency = engagementData.length ? engagementData.reduce((acc, curr) => acc + curr.consistency, 0) / engagementData.length : 0;
  const avgDepth = engagementData.length ? engagementData.reduce((acc, curr) => acc + curr.depth, 0) / engagementData.length : 0;
  const avgFocus = engagementData.length ? engagementData.reduce((acc, curr) => acc + curr.focus, 0) / engagementData.length : 0;

  const chartData = [
    { name: 'Rhythm Stability', value: avgConsistency, color: '#00bbf9' },
    { name: 'Curiosity Depth', value: avgDepth, color: '#ff3366' },
    { name: 'Active Presence', value: avgFocus, color: '#00f5d4' }
  ];

  const getScoreColor = (score: number) => {
    if (score > 80) return 'text-cyan-400';
    if (score > 50) return 'text-emerald-400';
    return 'text-amber-400';
  };

  const getScoreMessage = (score: number) => {
    if (score > 80) return "Flow State: Optimal learning and cognitive well-being.";
    if (score > 50) return "Healthy Drift: Normal exploration with steady presence.";
    return "Quiet Transition: The learner may benefit from a soft shift in environment.";
  };

  return (
    <div className="max-w-7xl mx-auto space-y-12">
      {/* Header Bio Section */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
         {[
           { label: 'Student', val: name },
           { label: 'Academic Level', val: grade || 'Unassigned' },
           { label: 'Chronological Age', val: age ? `${age} yrs` : 'N/A' },
           { label: 'Primary Focus', val: focusArea || 'Holistic' }
         ].map((item, i) => (
           <div key={i} className="tile p-6 flex flex-col items-center justify-center border-white/5 bg-stone-950/20 text-center">
              <span className="mono text-[8px] text-stone-600 uppercase tracking-[0.3em] mb-2">{item.label}</span>
              <span className="text-stone-200 font-light text-lg tracking-tight">{item.val}</span>
           </div>
         ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Prominent Score Tile */}
        <div className="tile rgb-border lg:col-span-5 p-12 flex flex-col items-center glow-blue bg-stone-950/40">
          <div className="tile-header w-full border-b border-white/5 pb-4 mb-10">
            <span className="rgb-text font-bold uppercase tracking-widest">Mental Engagement Score</span>
            <span className="text-stone-600 font-mono text-[8px]">ENCRYPTED_ID: {student.id.slice(-4)}</span>
          </div>

          <div className="relative w-64 h-64 mb-10">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={chartData}
                  cx="50%"
                  cy="50%"
                  innerRadius={85}
                  outerRadius={115}
                  paddingAngle={6}
                  dataKey="value"
