import React, { useState, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { AIPerspective } from '../types';

interface Props {
  insight: AIPerspective | null;
}

export const VintageAestheticTile: React.FC<Props> = ({ insight }) => {
  const [imageUrl, setImageUrl] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [loadingStep, setLoadingStep] = useState(0);
  const [hasApiKey, setHasApiKey] = useState(false);

  const loadingMessages = [
    "Developing film grain...",
    "Adjusting exposure curves...",
    "Capturing nostalgia...",
    "Applying warm tint...",
    "Rendering vintage finish..."
  ];

  useEffect(() => {
    const checkKey = async () => {
      // @ts-ignore - window.aistudio is injected
      const selected = await window.aistudio?.hasSelectedApiKey();
      setHasApiKey(!!selected);
    };
    checkKey();
  }, []);

  const handleOpenKeySelector = async () => {
    // @ts-ignore
    await window.aistudio?.openSelectKey();
    setHasApiKey(true);
  };

  const generateImage = async () => {
    if (!insight) return;
    setIsGenerating(true);
    setLoadingStep(0);

    const stepInterval = setInterval(() => {
      setLoadingStep(prev => (prev + 1) % loadingMessages.length);
    }, 2000);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const mood = insight.isStudying ? "serene and focused" : "dreamy and drifting";
      const basePrompt = `A high-quality vintage photograph with a ${mood} atmosphere. Warm film grain, nostalgic 1970s aesthetic, faded colors, cinematic lighting, soft focus, 35mm film style. The subject is an abstract representation of calm and nostalgia. Highly detailed, aesthetic composition.`;

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [{ text: basePrompt }],
        },
        config: {
          imageConfig: {
            aspectRatio: "16:9"
          }
        },
      });

      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          const base64EncodeString = part.inlineData.data;
          setImageUrl(`data:image/png;base64,${base64EncodeString}`);
          break;
        }
      }
    } catch (error: any) {
      console.error("Image Generation Error:", error);
      if (error?.message?.includes("entity was not found")) {
        setHasApiKey(false);
        alert("Please re-select your API key to continue.");
      }
    } finally {
      clearInterval(stepInterval);
      setIsGenerating(false);
    }
  };

  return (
    <div className="tile lg:col-span-5 p-6 flex flex-col h-[500px] relative overflow-hidden group">
      <div className="tile-header">
        <span>Vintage Aesthetic Visuals</span>
        <span className="mono text-[8px] opacity-40">Gemini Image Engine</span>
      </div>

      <div className="flex-1 flex flex-col items-center justify-center relative bg-black/40 rounded border border-stone-800/40 overflow-hidden">
        {!hasApiKey ? (
          <div className="text-center p-8 space-y-6">
            <div className="w-12 h-12 rounded-full border border-stone-800 flex items-center justify-center mx-auto mb-4">
              <svg className="w-6 h-6 text-stone-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" /></svg>
            </div>
            <p className="text-stone-400 text-sm italic font-light">Secure intelligence required for aesthetic generation.</p>
            <button 
              onClick={handleOpenKeySelector}
              className="px-6 py-2 bg-stone-100/5 border border-white/10 text-stone-300 mono text-[10px] tracking-widest hover:bg-white/10 transition-all uppercase"
            >
              Unlock Engine
            </button>
          </div>
        ) : isGenerating ? (
          <div className="text-center space-y-6 animate-pulse">
            <div className="relative w-16 h-16 mx-auto">
               <div className="absolute inset-0 border-2 border-stone-800 rounded-full"></div>
               <div className="absolute inset-0 border-2 border-stone-400 border-t-transparent rounded-full animate-spin"></div>
            </div>
            <div className="space-y-2">
              <p className="text-stone-300 font-light italic">{loadingMessages[loadingStep]}</p>
              <p className="text-stone-600 mono text-[9px] uppercase tracking-tighter">Gemini 2.5: Developing Image</p>
            </div>
          </div>
        ) : imageUrl ? (
          <div className="w-full h-full relative group/img">
            <img 
              src={imageUrl} 
              alt="Vintage Aesthetic"
              className="w-full h-full object-cover"
            />
            <div className="absolute inset-0 bg-black/40 opacity-0 group-hover/img:opacity-100 transition-opacity flex items-center justify-center">
               <button 
                onClick={generateImage}
                className="px-6 py-3 bg-white/10 backdrop-blur-md border border-white/20 text-white mono text-[10px] tracking-widest uppercase hover:bg-white/20"
               >
                 Capture New Moment
               </button>
            </div>
          </div>
        ) : (
          <div className="text-center p-8 space-y-4">
             <div className="text-4xl font-extralight text-stone-700 tracking-tighter mb-4 uppercase">Vintage Atmosphere</div>
             <p className="text-stone-500 text-xs font-light max-w-xs mx-auto mb-6">
               Synthesize a personalized vintage aesthetic image reflecting the current cognitive rhythm.
             </p>
             <button 
              onClick={generateImage}
              disabled={!insight}
              className="px-10 py-3 bg-stone-100 text-stone-900 font-medium text-[10px] tracking-widest hover:bg-white transition-all uppercase disabled:opacity-20"
             >
               Generate Vintage
             </button>
          </div>
        )}
      </div>

      <div className="mt-4 flex items-center justify-between text-[8px] mono text-stone-600 tracking-widest">
        <span>MODE: AESTHETIC_RECALL</span>
        <span>FORMAT: ANALOG_OPTIMIZED</span>
      </div>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { AIPerspective, AcademicMetrics } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getObservationalInsight(
  engagementData: any, 
  academicMetrics: AcademicMetrics, 
  remarks: string
): Promise<AIPerspective & { systemActions: string[] }> {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Analyze these behavioral patterns and academic data for a learner. 
    Provide a calm, non-judgmental observation and concrete recommendations for both parents and educators.

    Behavioral Patterns (7-day): ${JSON.stringify(engagementData)}
    Academic Metrics: ${JSON.stringify(academicMetrics)}
    Educator's Recent Remarks: "${remarks}"

    Guidelines:
    1. Do NOT use labels like "at risk", "failing", or "unstable".
    2. Focus on "drift", "rhythm", and "supportive alignment".
    3. The "suggestions" array is for parents/guardians (supportive, home-based).
    4. The "systemActions" array is for educators (professional, school-based interventions).
    5. Determine if the student is currently "Actively Studying" or showing "Potential Drift".

    The tone must be observational, precise, and supportive.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          observation: { type: Type.STRING },
          rationale: { type: Type.STRING },
          suggestions: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "Supportive advice for parents."
          },
          systemActions: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "Strategic actions for the teacher's response matrix."
          },
          isStudying: { type: Type.BOOLEAN },
          engagementScore: { type: Type.NUMBER }
        },
        required: ["observation", "rationale", "suggestions", "systemActions", "isStudying", "engagementScore"]
      }
    }
  });

  return JSON.parse(response.text.trim());
}

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { RealTimeClock } from './components/RealTimeClock';
import { getObservationalInsight } from './services/geminiService';
import { generateSyntheticData, generateAcademicMetrics } from './utils/dataGenerator';
import { AIPerspective, EngagementPoint, Student } from './types';
import { VintageAestheticTile } from './components/VideoVisualizationTile';
import { EngagementPatterns } from './components/Sections/EngagementPatterns';
import { DriftIndicators } from './components/Sections/DriftIndicators';
import { MomentSupport } from './components/Sections/MomentSupport';
import { NextSteps } from './components/Sections/NextSteps';
import { TeacherPortal } from './components/Sections/TeacherPortal';
import { ParentPortal } from './components/Sections/ParentPortal';
import { ProgressPortal } from './components/Sections/ProgressPortal';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer 
} from 'recharts';

const STORAGE_KEY_STUDENTS = 'lumina_students_collection';
const STORAGE_KEY_ACTIVE_ID = 'lumina_active_student_id';
const STORAGE_KEY_ROLE = 'lumina_user_role';

type ViewType = 'dashboard' | 'insights' | 'intelligence' | 'progress' | 'actions' | 'teacher' | 'parent';
type UserRole = 'student' | 'teacher' | 'parent';

const App: React.FC = () => {
  const [userRole, setUserRole] = useState<UserRole>(() => {
    return (localStorage.getItem(STORAGE_KEY_ROLE) as UserRole) || 'teacher';
  });

  const [students, setStudents] = useState<Student[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_STUDENTS);
    if (saved) return JSON.parse(saved);
    const initialStudent: Student = {
      id: 'default-01',
      name: 'Julian Vance',
      age: '16',
      grade: '11th',
      focusArea: 'Mathematics & Logic',
      remarks: 'Showing steady progress in rhythmic focus.',
      engagementData: generateSyntheticData(),
      academicMetrics: generateAcademicMetrics(),
      insight: null
    };
    return [initialStudent];
  });

  const [activeStudentId, setActiveStudentId] = useState<string>(() => {
    return localStorage.getItem(STORAGE_KEY_ACTIVE_ID) || 'default-01';
  });

  const [currentView, setCurrentView] = useState<ViewType>('dashboard');
  const [isLoading, setIsLoading] = useState(false);

  const activeStudent = useMemo(() => {
    return students.find(s => s.id === activeStudentId) || students[0];
  }, [students, activeStudentId]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_STUDENTS, JSON.stringify(students));
  }, [students]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_ACTIVE_ID, activeStudentId);
  }, [activeStudentId]);

  const initInsight = useCallback(async (student: Student, force = false) => {
    if (student.insight && !force) return;
    setIsLoading(true);
    try {
      const result = await getObservationalInsight(
        student.engagementData, 
        student.academicMetrics, 
        student.remarks
      );
      setStudents(prev => prev.map(s => s.id === student.id ? { ...s, insight: result } : s));
    } catch (error) {
      console.error("AI Insight error:", error);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    if (activeStudent && !activeStudent.insight) {
      initInsight(activeStudent);
    }
  }, [activeStudent, initInsight]);

  const updateStudent = (id: string, updates: Partial<Student>) => {
    setStudents(prev => {
      const next = prev.map(s => s.id === id ? { ...s, ...updates } : s);
      const updatedStudent = next.find(s => s.id === id);
      if (updatedStudent) {
        // We trigger an insight refresh when metrics or remarks are committed
        setTimeout(() => initInsight(updatedStudent, true), 100);
      }
      return next;
    });
  };

  const addStudent = (name: string) => {
    const newStudent: Student = {
      id: `std-${Date.now()}`,
      name,
      remarks: '',
      engagementData: generateSyntheticData(),
      academicMetrics: generateAcademicMetrics(),
      insight: null
    };
    setStudents(prev => [...prev, newStudent]);
    setActiveStudentId(newStudent.id);
  };

  const handleRoleChange = (role: UserRole) => {
    setUserRole(role);
    localStorage.setItem(STORAGE_KEY_ROLE, role);
    setCurrentView('dashboard');
  };

  const allNavItems: { label: string; id: ViewType; roles: UserRole[] }[] = [
    { label: 'Dashboard', id: 'dashboard', roles: ['student', 'teacher', 'parent'] },
    { label: 'Insights', id: 'insights', roles: ['student', 'teacher'] },
    { label: 'Intelligence', id: 'intelligence', roles: ['student', 'teacher', 'parent'] },
    { label: 'Progress', id: 'progress', roles: ['student', 'teacher', 'parent'] },
    { label: 'Teacher Log', id: 'teacher', roles: ['teacher'] },
    { label: 'Parent Portal', id: 'parent', roles: ['parent', 'teacher'] },
    { label: 'System Actions', id: 'actions', roles: ['teacher'] },
  ];

  const visibleNavItems = allNavItems.filter(item => item.roles.includes(userRole));

  const handleNextView = () => {
    const currentIndex = visibleNavItems.findIndex(item => item.id === currentView);
    if (currentIndex < visibleNavItems.length - 1) {
      setCurrentView(visibleNavItems[currentIndex + 1].id);
    } else {
      setCurrentView('dashboard');
    }
  };

  const renderViewContent = () => {
    if (!activeStudent) return <div className="text-center text-stone-500 py-20">No active student selected.</div>;

    switch (currentView) {
      case 'insights':
        return (
          <div className="space-y-12 animate-in">
            <EngagementPatterns data={activeStudent.engagementData} />
            <DriftIndicators />
          </div>
        );
      case 'intelligence':
        return (
          <div className="space-y-8 animate-in">
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
              <div className="lg:col-span-12">
                <MomentSupport insight={activeStudent.insight} isLoading={isLoading} />
              </div>
              <div className="lg:col-span-12 flex justify-center">
                <div className="w-full max-w-4xl">
                  <VintageAestheticTile insight={activeStudent.insight} />
                </div>
              </div>
            </div>
          </div>
        );
      case 'progress':
        return (
          <div className="animate-in">
            <ProgressPortal student={activeStudent} />
          </div>
        );
      case 'teacher':
        return (
          <div className="animate-in">
            <TeacherPortal 
              student={activeStudent}
              students={students}
              onSelectStudent={setActiveStudentId}
              onAddStudent={addStudent}
              onUpdateStudent={(updates) => updateStudent(activeStudent.id, updates)}
            />
          </div>
        );
      case 'parent':
        return (
          <div className="animate-in">
            <ParentPortal 
              student={activeStudent}
            />
          </div>
        );
      case 'actions':
        return (
          <div className="animate-in">
            <NextSteps insight={activeStudent.insight} />
          </div>
        );
      case 'dashboard':
      default:
        return (
          <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-6 animate-in">
            <div className="tile rgb-border lg:col-span-4 p-6 flex flex-col h-[500px]">
              <div className="tile-header">
                <span className="rgb-text font-bold">Rhythm: {activeStudent.name}</span>
                <span className="text-cyan-400 font-mono">
                  {userRole === 'parent' ? 'Well-being: ' : ''}{activeStudent.insight?.engagementScore || '--'}%
                </span>
              </div>
              <div className="flex-1 overflow-hidden">
                <div className="text-3xl font-light text-stone-100 mb-6 tracking-tight">Rhythm Analytics</div>
                <div className="h-[200px] w-full">
                  <ResponsiveContainer width="100%" height="100%">
                    <AreaChart data={activeStudent.engagementData}>
                      <defs>
                        <linearGradient id="colorCons" x1="0" y1="0" x2="0" y2="1">
                          <stop offset="5%" stopColor="#00bbf9" stopOpacity={0.4}/>
                          <stop offset="95%" stopColor="#00bbf9" stopOpacity={0}/>
                        </linearGradient>
                      </defs>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="rgba(255,255,255,0.05)" />
                      <XAxis dataKey="time" axisLine={false} tickLine={false} tick={{fill: '#78716c', fontSize: 10}} />
                      <YAxis hide />
                      <Area type="monotone" dataKey="consistency" stroke="#00bbf9" fillOpacity={1} fill="url(#colorCons)" strokeWidth={2} />
                    </AreaChart>
                  </ResponsiveContainer>
                </div>
                <div className="mt-6 space-y-4">
                  {['Focus (Cyan)', 'Depth (Magenta)', 'Presence (Teal)'].map((sub, i) => (
                    <div key={sub} className="flex items-center gap-3">
                      <span className="text-[10px] mono text-stone-500 w-28">{sub}</span>
                      <div className="flex-1 h-[3px] bg-stone-900 rounded-full overflow-hidden">
                        <div className="h-full" style={{
                          width: `${80 - (i*15)}%`, 
                          backgroundColor: i === 0 ? '#00bbf9' : i === 1 ? '#ff3366' : '#00f5d4',
                          boxShadow: `0 0 10px ${i === 0 ? '#00bbf9' : i === 1 ? '#ff3366' : '#00f5d4'}`
                        }}></div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            {/* Aesthetic Visual Tile */}
            <VintageAestheticTile insight={activeStudent.insight} />

            <div className="tile rgb-border lg:col-span-3 p-6 h-[500px]">
              <div className="tile-header">
                <span className="text-magenta-400">Markers</span>
