                    <span className="text-stone-300 text-xs">{activeStudent.grade || 'N/A'} — {activeStudent.age || 'N/A'} y/o</span>
                 </div>
                 <div className="flex flex-col gap-1 p-3 bg-stone-950/40 border border-white/5 rounded">
