              onClick={() => setCurrentView(item.id)}
              className={`bouncy-tab transition-all duration-300 pb-1 whitespace-nowrap relative ${
                currentView === item.id ? 'text-white font-bold' : 'text-stone-500 hover:text-stone-200'
              }`}
            >
              {item.label}
