  const handleSave = () => {
    onUpdateStudent(formData);
  };

  const updateMetric = (key: keyof AcademicMetrics, value: any) => {
    setFormData(prev => ({
      ...prev,
      academicMetrics: {
        ...prev.academicMetrics,
        [key]: value
