                  <div className="mb-6">
                    <div className="mono text-[8px] text-stone-600 uppercase mb-1">Academic Decision</div>
                    <div className={`text-2xl font-light italic tracking-tight ${studentRisk?.risk_label === 1 ? 'text-red-500' : 'text-emerald-500'}`}>
