        </div>
      </nav>

      <div className="text-center mb-20 space-y-6">
        <h1 className="serif text-6xl md:text-8xl text-stone-50 tracking-tighter font-light uppercase">
          {activeStudent ? activeStudent.name : 'NULL_ENTITY'}
