        </div>
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip as RechartsTooltip, BarChart, Bar, XAxis, YAxis } from 'recharts';
import { Student } from '../../types';

interface Props {
  student: Student;
}

export const ParentPortal: React.FC<Props> = ({ student }) => {
  const { name, age, grade, focusArea, remarks, engagementData, insight, academicMetrics } = student;

  const avgConsistency = engagementData.length ? engagementData.reduce((acc, curr) => acc + curr.consistency, 0) / engagementData.length : 0;
  const avgDepth = engagementData.length ? engagementData.reduce((acc, curr) => acc + curr.depth, 0) / engagementData.length : 0;
  const avgFocus = engagementData.length ? engagementData.reduce((acc, curr) => acc + curr.focus, 0) / engagementData.length : 0;

  const chartData = [
    { name: 'Consistency Rhythm', value: avgConsistency, color: '#00bbf9' },
    { name: 'Cognitive Depth', value: avgDepth, color: '#ff3366' },
    { name: 'Active Presence', value: avgFocus, color: '#00f5d4' }
  ];

  // Real-time Academic Indicators for the matrix
  const academicIndicators = [
    { label: 'Submissions', value: academicMetrics.assignmentSubmissionCount, max: 40, color: 'bg-cyan-500' },
    { label: 'Attendance', value: 100 - academicMetrics.attendanceDropPercentage, max: 100, color: 'bg-emerald-500' },
    { label: 'Timeliness', value: (1 - academicMetrics.lateSubmissionRatio) * 100, max: 100, color: 'bg-magenta-500' },
    { label: 'Streak Stability', value: Math.max(0, 5 - academicMetrics.missingAssignmentStreak) * 20, max: 100, color: 'bg-amber-500' }
  ];

  const getSyncStatus = (score: number) => {
    if (score > 85) return { label: 'SYNCHRONIZED', color: 'text-cyan-400', bg: 'bg-cyan-500/10', border: 'border-cyan-500/30' };
    if (score > 70) return { label: 'FLOW_ACTIVE', color: 'text-emerald-400', bg: 'bg-emerald-500/10', border: 'border-emerald-500/30' };
    if (score > 50) return { label: 'OBSERVING', color: 'text-amber-400', bg: 'bg-amber-500/10', border: 'border-amber-500/30' };
    return { label: 'ALIGNMENT_REQ', color: 'text-rose-400', bg: 'bg-rose-500/10', border: 'border-rose-500/30' };
  };

  const score = insight?.engagementScore || 0;
  const status = getSyncStatus(score);

  const getParentAdvice = (score: number) => {
    if (score > 85) return "Deep synchronization achieved. Your child is navigating complex learning layers with high rhythmic precision.";
    if (score > 70) return "Active flow detected. Patterns show a healthy balance of exploration and focused inquiry.";
    if (score > 50) return "Slight rhythmic drift observed. This suggests a transition phase where supportive environmental cues might be helpful.";
    return "Alignment is currently low. This is a gentle opportunity for a restorative pause or a shift in learning focus.";
  };

  return (
    <div className="max-w-7xl mx-auto space-y-12">
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
         {[
           { label: 'Student', val: name },
           { label: 'Academic Level', val: grade || 'Unassigned' },
           { label: 'Chronological Age', val: age ? `${age} yrs` : 'N/A' },
           { label: 'Primary Focus', val: focusArea || 'Holistic' }
         ].map((item, i) => (
           <div key={i} className="tile p-6 flex flex-col items-center justify-center border-white/5 bg-stone-950/20 text-center transition-transform hover:scale-[1.02]">
              <span className="mono text-[8px] text-stone-600 uppercase tracking-[0.3em] mb-2">{item.label}</span>
              <span className="text-stone-200 font-light text-lg tracking-tight">{item.val}</span>
           </div>
         ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="tile rgb-border lg:col-span-7 p-10 flex flex-col glow-blue bg-stone-950/40 relative">
          <div className="tile-header w-full border-b border-white/5 pb-4 mb-8">
            <span className="rgb-text font-bold uppercase tracking-[0.2em]">Rhythmic Engagement Matrix</span>
            <span className="text-stone-600 font-mono text-[8px]">LIVE_FEED: {student.id.slice(-4)}</span>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-10 items-center">
            <div className="relative">
              <div className="relative w-64 h-64 mx-auto">
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Pie
                      data={chartData}
                      cx="50%"
                      cy="50%"
                      innerRadius={85}
                      outerRadius={110}
                      paddingAngle={8}
                      dataKey="value"
                      stroke="none"
                    >
                      {chartData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={entry.color} fillOpacity={0.8} />
                      ))}
                    </Pie>
                    <RechartsTooltip 
                      contentStyle={{ backgroundColor: '#060505', border: '1px solid rgba(255,255,255,0.1)', fontSize: '11px', borderRadius: '12px', color: '#fff' }}
                    />
                  </PieChart>
                </ResponsiveContainer>
                <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                   <span className={`text-6xl font-light tracking-tighter ${status.color}`}>
                     {score}%
                   </span>
                   <span className="mono text-[8px] text-stone-500 uppercase tracking-[0.3em] mt-2">Sync Level</span>
                </div>
              </div>
              <div className="mt-8 grid grid-cols-1 gap-2">
                 {chartData.map((item) => (
                    <div key={item.name} className="flex items-center justify-between px-4 py-2 bg-white/[0.02] border border-white/5 rounded-lg">
                       <div className="flex items-center gap-2">
                          <div className="w-2 h-2 rounded-full" style={{ backgroundColor: item.color, boxShadow: `0 0 8px ${item.color}` }}></div>
                          <span className="mono text-[8px] text-stone-400 uppercase tracking-widest">{item.name}</span>
                       </div>
                       <span className="mono text-[10px] text-stone-200 font-bold">{item.value.toFixed(0)}%</span>
                    </div>
                 ))}
              </div>
            </div>

            <div className="space-y-6">
              <div className="p-4 bg-white/[0.03] border border-white/10 rounded-2xl relative overflow-hidden">
                <div className="absolute top-0 right-0 p-2">
                  <div className={`px-2 py-0.5 rounded-full border ${status.bg} ${status.border} ${status.color} mono text-[7px] tracking-widest font-bold`}>
                    {status.label}
                  </div>
                </div>
                <h4 className="mono text-[9px] text-stone-500 uppercase tracking-widest mb-6">Academic Rhythm Indicators</h4>
                <div className="space-y-5">
                  {academicIndicators.map((indicator, idx) => (
                    <div key={idx} className="space-y-2">
                      <div className="flex justify-between items-center px-1">
                        <span className="mono text-[8px] text-stone-400 uppercase tracking-wider">{indicator.label}</span>
                        <span className="mono text-[9px] text-stone-200 font-bold">
                          {indicator.label === 'Attendance' || indicator.label === 'Timeliness' || indicator.label === 'Streak Stability' 
                            ? `${indicator.value.toFixed(0)}%` 
                            : indicator.value}
                        </span>
                      </div>
                      <div className="h-[2px] w-full bg-stone-900 rounded-full overflow-hidden">
                        <div 
                          className={`h-full transition-all duration-1000 ease-out ${indicator.color}`} 
                          style={{ width: `${(indicator.value / indicator.max) * 100}%` }}
                        />
                      </div>
                    </div>
                  ))}
                </div>
              </div>
              <div className="p-4 bg-stone-900/40 border border-white/5 rounded-2xl">
                 <p className="text-stone-400 text-[11px] font-light italic leading-relaxed">
                   "The data matrix above is synthesized from active teacher logs and behavioral sensing layers, refreshed in real-time as educators update the student's profile."
                 </p>
              </div>
            </div>
          </div>
        </div>

        <div className="tile rgb-border lg:col-span-5 p-10 flex flex-col justify-center bg-gradient-to-br from-stone-900/40 to-stone-950/70">
          <div className="tile-header mb-8">
            <span className="text-cyan-400 font-bold uppercase tracking-widest">Supportive Alignment Plan</span>
            <span className="text-stone-500 mono text-[8px]">AI_GUIDE: ENABLED</span>
          </div>

          <div className="space-y-10">
            <div className="space-y-4">
              <span className="mono text-[9px] text-magenta-500 uppercase tracking-widest font-bold">Rhythmic Analysis</span>
              <h3 className="serif text-2xl md:text-3xl text-stone-50 font-light leading-[1.3] italic tracking-tight border-l-2 border-magenta-500/30 pl-8">
                "{insight?.observation || 'Synthesizing the last 168 hours of behavioral patterns...'}"
              </h3>
            </div>

            <div className="h-[1px] w-full bg-gradient-to-r from-white/10 via-white/5 to-transparent"></div>

            <div className="space-y-6">
               <h4 className="mono text-[10px] text-white uppercase tracking-[0.4em] font-bold">AI Recommended Actions</h4>
               <div className="space-y-3">
                  {(insight?.suggestions || ['Synchronizing teacher logs and academic metrics...']).map((s, i) => (
                    <div key={i} className="flex gap-4 p-4 bg-white/[0.03] border border-white/10 rounded-xl transition-all hover:bg-white/[0.05] group">
                       <span className="text-magenta-500 mono font-bold text-xs">0{i+1}</span>
                       <span className="text-stone-300 text-xs font-light leading-relaxed">{s}</span>
                    </div>
                  ))}
               </div>
            </div>
          </div>
        </div>

        <div className="tile rgb-border lg:col-span-12 p-10 bg-stone-950/60 relative overflow-hidden group">
          <div className="tile-header">
            <span className="rgb-text font-bold uppercase tracking-widest">Educator's Session Reflections</span>
            <span className="text-stone-600 font-mono text-[8px]">ACCESS: SECURE_SYNC</span>
          </div>
          <div className="mt-6 flex flex-col md:flex-row gap-12 items-start">
             <div className="w-20 h-20 rounded-3xl border border-white/5 bg-stone-900 flex-shrink-0 flex items-center justify-center glow-red shadow-inner transition-transform group-hover:rotate-3">
                <svg className="w-10 h-10 text-magenta-500 opacity-40" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                </svg>
             </div>
             <div className="flex-1 space-y-6">
                <p className="text-stone-200 font-light italic leading-relaxed text-2xl md:text-3xl max-w-6xl">
                  {remarks ? `"${remarks}"` : "The educator has not provided qualitative session reflections for this cycle."}
                </p>
                <div className="flex flex-col sm:flex-row justify-between items-center border-t border-white/5 pt-8 gap-4">
                   <div className="mono text-[9px] text-stone-600 uppercase tracking-widest">Privacy Protocol: Hashed for Confidentiality</div>
                   <button className="liquid-button text-[10px] mono text-cyan-400 hover:text-cyan-300 transition-all uppercase tracking-[0.2em] border border-cyan-400/20 px-6 py-2 rounded-full bg-stone-950/40">Request Full Session Log &gt;</button>
                </div>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export interface Observation {
  id: string;
  type: 'participation' | 'tempo' | 'focus';
  description: string;
  intensity: 'subtle' | 'moderate';
}

export interface EngagementPoint {
  time: string;
  consistency: number;
  depth: number;
  focus: number;
}

export interface AIPerspective {
  observation: string;
  rationale: string;
  suggestions: string[];
  isStudying: boolean;
  engagementScore: number;
}

export interface AcademicMetrics {
  assignmentSubmissionCount: number;
  attendanceDropPercentage: number;
  marksDropBetweenTerms: number;
  lateSubmissionRatio: number;
  attendanceTrend: 'rising' | 'falling' | 'stable';
  gradeVariance: number;
  missingAssignmentStreak: number;
}

export interface Message {
  id: string;
  sender: 'Teacher' | 'System';
  text: string;
  timestamp: string;
}

export interface Student {
  id: string;
  name: string;
  age?: string;
  grade?: string;
  focusArea?: string;
  subjectEmoji?: string;
  remarks: string;
  engagementData: EngagementPoint[];
  academicMetrics: AcademicMetrics;
  insight: AIPerspective | null;
  messages: Message[];
}

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { RealTimeClock } from './components/RealTimeClock';
import { getObservationalInsight } from './services/geminiService';
import { generateSyntheticData, generateAcademicMetrics } from './utils/dataGenerator';
import { AIPerspective, EngagementPoint, Student, Message } from './types';
import { VintageAestheticTile } from './components/VideoVisualizationTile';
import { EngagementPatterns } from './components/Sections/EngagementPatterns';
import { DriftIndicators } from './components/Sections/DriftIndicators';
import { MomentSupport } from './components/Sections/MomentSupport';
import { NextSteps } from './components/Sections/NextSteps';
import { TeacherPortal } from './components/Sections/TeacherPortal';
import { ParentPortal } from './components/Sections/ParentPortal';
import { ProgressPortal } from './components/Sections/ProgressPortal';
import { predictStudentRisk } from './utils/mlEngine';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer 
} from 'recharts';

const STORAGE_KEY_STUDENTS = 'lumina_students_collection';
const STORAGE_KEY_ACTIVE_ID = 'lumina_active_student_id';
const STORAGE_KEY_ROLE = 'lumina_user_role';

type ViewType = 'dashboard' | 'insights' | 'intelligence' | 'progress' | 'actions' | 'teacher' | 'parent';
type UserRole = 'student' | 'teacher' | 'parent';

const App: React.FC = () => {
  const [userRole, setUserRole] = useState<UserRole>(() => {
    return (localStorage.getItem(STORAGE_KEY_ROLE) as UserRole) || 'teacher';
  });

  const [students, setStudents] = useState<Student[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_STUDENTS);
    if (saved) return JSON.parse(saved);
    return []; // Start with no names, no Julian, no RAM.
  });

  const [activeStudentId, setActiveStudentId] = useState<string>(() => {
    return localStorage.getItem(STORAGE_KEY_ACTIVE_ID) || '';
  });

  const [currentView, setCurrentView] = useState<ViewType>('dashboard');
  const [isLoading, setIsLoading] = useState(false);

  const activeStudent = useMemo(() => {
    if (students.length === 0) return null;
    return students.find(s => s.id === activeStudentId) || students[0];
  }, [students, activeStudentId]);

  const studentRisk = useMemo(() => {
    if (!activeStudent) return null;
    return predictStudentRisk(activeStudent.academicMetrics);
  }, [activeStudent]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_STUDENTS, JSON.stringify(students));
  }, [students]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_ACTIVE_ID, activeStudentId || '');
  }, [activeStudentId]);

  const initInsight = useCallback(async (student: Student, force = false) => {
    if (student.insight && !force) return;
    setIsLoading(true);
    try {
      const result = await getObservationalInsight(
        student.engagementData, 
        student.academicMetrics, 
        student.remarks
      );
      setStudents(prev => prev.map(s => s.id === student.id ? { ...s, insight: result } : s));
    } catch (error) {
      console.error("AI Insight error:", error);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    if (activeStudent && !activeStudent.insight) {
      initInsight(activeStudent);
    }
  }, [activeStudent, initInsight]);

  const updateStudent = (id: string, updates: Partial<Student>) => {
    setStudents(prev => {
      const next = prev.map(s => s.id === id ? { ...s, ...updates } : s);
      const updatedStudent = next.find(s => s.id === id);
      if (updatedStudent && updates.academicMetrics) {
        // Trigger re-insight if metrics change significantly
        setTimeout(() => initInsight(updatedStudent, true), 100);
      }
      return next;
    });
  };

  const addStudent = (name: string) => {
    const newStudent: Student = {
      id: `std-${Date.now()}`,
      name,
      remarks: '',
      subjectEmoji: '🌀',
      engagementData: generateSyntheticData(),
      academicMetrics: generateAcademicMetrics(),
      insight: null,
      messages: []
    };
    setStudents(prev => [...prev, newStudent]);
    setActiveStudentId(newStudent.id);
  };

  const deleteStudent = (id: string) => {
    setStudents(prev => {
      const next = prev.filter(s => s.id !== id);
      return next;
    });

    if (activeStudentId === id) {
      setActiveStudentId('');
    }
  };

  const handleSendMessage = (studentId: string, text: string) => {
    const newMessage: Message = {
      id: `msg-${Date.now()}`,
      sender: 'Teacher',
      text,
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    };
    setStudents(prev => prev.map(s => s.id === studentId ? { ...s, messages: [...s.messages, newMessage] } : s));
  };

  const handleRoleChange = (role: UserRole) => {
    setUserRole(role);
    localStorage.setItem(STORAGE_KEY_ROLE, role);
    setCurrentView('dashboard');
  };

  const allNavItems: { label: string; id: ViewType; roles: UserRole[] }[] = [
    { label: 'Dashboard', id: 'dashboard', roles: ['student', 'teacher', 'parent'] },
    { label: 'Insights', id: 'insights', roles: ['student', 'teacher'] },
    { label: 'Intelligence', id: 'intelligence', roles: ['student', 'teacher', 'parent'] },
    { label: 'Progress', id: 'progress', roles: ['student', 'teacher', 'parent'] },
    { label: 'Teacher Log', id: 'teacher', roles: ['teacher'] },
    { label: 'Parent Portal', id: 'parent', roles: ['parent', 'teacher'] },
    { label: 'System Actions', id: 'actions', roles: ['teacher'] },
  ];

  const visibleNavItems = allNavItems.filter(item => item.roles.includes(userRole));

  const handleNextView = () => {
    const currentIndex = visibleNavItems.findIndex(item => item.id === currentView);
    if (currentIndex < visibleNavItems.length - 1) {
      setCurrentView(visibleNavItems[currentIndex + 1].id);
    } else {
      setCurrentView('dashboard');
    }
  };

  const renderViewContent = () => {
    if (currentView === 'teacher') {
      return (
        <TeacherPortal 
          student={activeStudent}
          students={students}
          onSelectStudent={setActiveStudentId}
          onAddStudent={addStudent}
          onDeleteStudent={deleteStudent}
          onUpdateStudent={(updates) => activeStudent && updateStudent(activeStudent.id, updates)}
          onSendMessage={(text) => activeStudent && handleSendMessage(activeStudent.id, text)}
        />
      );
    }

    if (!activeStudent) {
      return (
        <div className="flex flex-col items-center justify-center py-40 space-y-8 animate-in fade-in slide-in-from-bottom-10 duration-1000">
           <div className="relative">
              <div className="absolute inset-0 bg-cyan-500/20 blur-3xl rounded-full"></div>
              <div className="relative text-stone-700 mono text-[10px] tracking-[0.8em] uppercase border border-stone-800 px-8 py-3 rounded-full backdrop-blur-sm">
                SYSTEM_STATE: NULL_REGISTRY
              </div>
           </div>
           <div className="text-center space-y-4">
              <h2 className="serif text-5xl md:text-7xl text-stone-500 italic font-light tracking-tighter opacity-40">Registry is empty.</h2>
              <p className="text-stone-600 mono text-xs uppercase tracking-widest max-w-sm mx-auto leading-relaxed">
                No names detected. Initialize the educator sensing layer to begin monitoring cognitive learning drift.
              </p>
           </div>
           <button 
             onClick={() => setCurrentView('teacher')} 
             className="liquid-button px-12 py-4 bg-stone-100 text-stone-950 font-bold mono text-[10px] tracking-widest uppercase rounded-full shadow-[0_0_30px_rgba(255,255,255,0.1)]"
           >
             Open Teacher Log
           </button>
        </div>
      );
    }

    const themeColor = studentRisk?.risk_label === 1 ? '#ff3366' : '#00bbf9';
    const glowClass = studentRisk?.risk_label === 1 ? 'glow-red' : 'glow-blue';

    switch (currentView) {
      case 'insights':
        return (
          <div className="space-y-12">
            <EngagementPatterns data={activeStudent.engagementData} />
            <DriftIndicators />
          </div>
        );
      case 'intelligence':
        return (
          <div className="space-y-8">
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
              <div className="lg:col-span-12">
                <MomentSupport insight={activeStudent.insight} isLoading={isLoading} />
              </div>
              <div className="lg:col-span-12 flex justify-center">
                <div className="w-full max-w-4xl">
                  <VintageAestheticTile insight={activeStudent.insight} />
                </div>
              </div>
            </div>
          </div>
        );
      case 'progress':
        return (
          <ProgressPortal student={activeStudent} />
        );
      case 'parent':
        return (
          <ParentPortal 
            student={activeStudent}
          />
        );
      case 'actions':
        return (
          <NextSteps insight={activeStudent.insight} />
        );
      case 'dashboard':
      default:
        return (
          <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-6">
            <div className={`tile rgb-border lg:col-span-4 p-6 flex flex-col h-[500px] ${glowClass}`}>
              <div className="tile-header">
                <span className="rgb-text font-bold uppercase tracking-widest">Rhythm Scan</span>
                <span className="mono text-[8px] opacity-40">AUTO_MODE: ON</span>
              </div>
              <div className="flex-1 overflow-hidden">
                <div className="text-3xl font-light text-stone-100 mb-6 tracking-tight flex items-center gap-4">
                    Analytical Core
                    <div className={`w-2 h-2 rounded-full animate-pulse`} style={{ backgroundColor: themeColor }}></div>
                </div>
                <div className="h-[200px] w-full">
                  <ResponsiveContainer width="100%" height="100%">
                    <AreaChart data={activeStudent.engagementData}>
                      <defs>
                        <linearGradient id="dynamicColor" x1="0" y1="0" x2="0" y2="1">
                          <stop offset="5%" stopColor={themeColor} stopOpacity={0.4}/>
                          <stop offset="95%" stopColor={themeColor} stopOpacity={0}/>
                        </linearGradient>
                      </defs>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="rgba(255,255,255,0.05)" />
                      <XAxis dataKey="time" axisLine={false} tickLine={false} tick={{fill: '#78716c', fontSize: 10}} />
                      <Area type="monotone" dataKey="consistency" stroke={themeColor} fillOpacity={1} fill="url(#dynamicColor)" strokeWidth={2} />
                    </AreaChart>
                  </ResponsiveContainer>
                </div>
                <div className="mt-6 space-y-4">
                  {['Consistency', 'Depth', 'Presence'].map((sub, i) => (
                    <div key={sub} className="flex items-center gap-3">
                      <span className="text-[10px] mono text-stone-500 w-28 uppercase tracking-widest">{sub}</span>
                      <div className="flex-1 h-[3px] bg-stone-900 rounded-full overflow-hidden">
                        <div className="h-full transition-all duration-1000" style={{
                          width: `${85 - (i*12)}%`, 
                          backgroundColor: i === 0 ? themeColor : i === 1 ? '#ff3366' : '#00f5d4',
                          boxShadow: `0 0 10px ${i === 0 ? themeColor : i === 1 ? '#ff3366' : '#00f5d4'}`
                        }}></div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            <VintageAestheticTile insight={activeStudent.insight} />

            <div className={`tile rgb-border lg:col-span-3 p-6 h-[500px] ${glowClass}`}>
              <div className="tile-header">
                <span className="mono text-[10px] tracking-widest uppercase text-stone-400">Markers</span>
              </div>

              <div className="flex flex-col h-full">
                  <div className="mb-6 flex items-center gap-4">
                    <div className="w-16 h-16 rounded-2xl bg-white/[0.03] border border-white/5 flex items-center justify-center text-4xl animate-pulse shadow-[0_0_20px_rgba(255,255,255,0.05)]">
                      {activeStudent.subjectEmoji || '🌀'}
                    </div>
                    <div>
                      <div className="mono text-[8px] text-stone-600 uppercase mb-1">Subject Sigil</div>
                      <div className="text-xl font-light text-stone-200 tracking-tight leading-none uppercase">
                        {activeStudent.focusArea?.split(' ')[0] || 'Flow'}
                      </div>
                    </div>
                  </div>

                  <div className="mb-6">
                    <div className="mono text-[8px] text-stone-600 uppercase mb-1">Academic Decision</div>
                    <div className={`text-2xl font-light italic tracking-tight ${studentRisk?.risk_label === 1 ? 'text-red-500' : 'text-emerald-500'}`}>
                        {studentRisk?.academic_help_required === "Yes" ? "Assistance Required" : "Steady Flow"}
                    </div>
                  </div>

                  <div className="space-y-4 flex-1">
                    <div className="flex flex-col gap-1 p-3 bg-stone-950/40 border border-white/5 rounded group hover:border-white/10 transition-colors">
                        <span className="mono text-[8px] text-stone-500 uppercase tracking-widest">Grade / Age</span>
                        <span className="text-stone-300 text-xs font-medium">{activeStudent.grade || 'N/A'} — {activeStudent.age || 'N/A'} y/o</span>
                    </div>
                    <div className="p-4 bg-stone-900/60 border border-stone-800/80 rounded flex justify-between items-start transition-all hover:scale-[1.02] cursor-default relative overflow-hidden">
                      <div className="relative z-10">
                        <div className="text-xs text-stone-100 font-medium mb-1">Attention Trace</div>
                        <div className={`text-[10px] mono uppercase tracking-widest font-bold ${studentRisk?.risk_label === 1 ? 'text-red-500/80' : 'text-cyan-500/80'}`}>
                            {studentRisk?.risk_label === 1 ? 'ALERT_LEVEL_HIGH' : 'NOMINAL_STATE'}
                        </div>
                      </div>
                      <div className={`absolute top-0 right-0 h-full w-1 ${studentRisk?.risk_label === 1 ? 'bg-red-500' : 'bg-cyan-500'}`}></div>
                    </div>
                  </div>

                  {activeStudent.remarks && (
                    <div className="mt-8 border-t border-white/5 pt-4">
                      <div className="text-[8px] mono text-stone-500 uppercase tracking-widest mb-2">Latest Educator Remark</div>
                      <p className="text-[10px] text-stone-400 italic line-clamp-4 leading-relaxed bg-stone-950/20 p-2 rounded">
                        "{activeStudent.remarks}"
                      </p>
                    </div>
                  )}
              </div>
            </div>

            <div className={`tile rgb-border lg:col-span-12 p-8 relative overflow-hidden ${glowClass}`}>
              <div className="flex flex-col md:flex-row items-center justify-between gap-6 relative z-10">
                <div className="space-y-1 text-center md:text-left">
                  <div className="flex items-center gap-3 justify-center md:justify-start">
                    <div className="mono text-[10px] text-stone-400 uppercase tracking-widest">Sensing Identity</div>
                    <div className="h-[1px] w-8 bg-stone-800"></div>
                    <div className="mono text-[10px] text-cyan-400 uppercase font-bold">{activeStudent.id.slice(-6)}</div>
                  </div>
                  <div className="text-2xl font-light text-stone-100 italic">"{activeStudent.insight?.observation || 'Synthesizing cognitive patterns...'}"</div>
                </div>
                <div className="flex flex-wrap justify-center gap-4">
                  {userRole === 'teacher' && (
                    <button onClick={() => setCurrentView('teacher')} className="liquid-button px-6 py-2 bg-stone-950 border border-magenta-500/30 text-magenta-400 mono text-[10px] tracking-widest hover:bg-magenta-900/20 transition-all uppercase rounded-full glow-red">Config Profile</button>
                  )}
                  {userRole === 'parent' && (
                    <button onClick={() => setCurrentView('parent')} className="liquid-button px-6 py-2 bg-stone-950 border border-cyan-500/30 text-cyan-400 mono text-[10px] tracking-widest hover:bg-cyan-900/20 transition-all uppercase rounded-full glow-blue">Sync Data</button>
                  )}
                  <button onClick={() => setCurrentView('intelligence')} className="liquid-button px-6 py-2 bg-stone-100 text-stone-950 font-bold mono text-[10px] tracking-widest hover:bg-white transition-all uppercase rounded-full">Intel Report</button>
                </div>
              </div>
              <div className="absolute bottom-0 left-0 w-full h-[2px] bg-gradient-to-r from-transparent via-cyan-500 via-magenta-500 via-emerald-500 to-transparent opacity-30"></div>
            </div>
          </div>
        );
    }
  };

  return (
    <div className="dashboard-overlay min-h-screen p-6 md:p-12 overflow-y-auto relative">
      <nav className="flex flex-col md:flex-row justify-between items-center mb-16 border-b border-white/5 pb-6 sticky top-0 bg-stone-950/70 backdrop-blur-3xl z-[100] gap-4">
        <div className="flex flex-wrap justify-center md:justify-start gap-2 md:gap-4 mono text-[10px] tracking-[0.2em] uppercase p-2">
          {visibleNavItems.map((item) => (
            <button
              key={item.id}
              onClick={() => setCurrentView(item.id)}
              className={`liquid-button px-4 py-2 whitespace-nowrap relative rounded-lg border border-transparent transition-all duration-300 ${
                currentView === item.id 
                  ? 'text-white font-bold bg-white/10 border-white/10' 
                  : 'text-stone-500 hover:text-stone-200 hover:bg-stone-900/40'
              }`}
            >
              {item.label}
              {currentView === item.id && (
                <span className="tab-indicator absolute -bottom-[25px] left-0 w-full h-[2px] bg-gradient-to-r from-cyan-500 to-magenta-500 shadow-[0_0_10px_#00bbf9]"></span>
              )}
            </button>
          ))}
        </div>

        <div className="flex items-center gap-6">
          <div className="flex bg-stone-950 border border-white/10 rounded-full p-1 shadow-inner">
            {(['student', 'teacher', 'parent'] as UserRole[]).map(role => (
              <button
                key={role}
                onClick={() => handleRoleChange(role)}
                className={`liquid-button px-4 py-1.5 text-[8px] mono rounded-full transition-all uppercase ${userRole === role ? 'bg-white text-stone-950 font-bold' : 'text-stone-600 hover:text-stone-300'}`}
              >
                {role}
              </button>
            ))}
          </div>
        </div>
      </nav>

      <div className="text-center mb-20 space-y-6">
        <h1 className="serif text-6xl md:text-8xl text-stone-50 tracking-tighter font-light uppercase">
          {activeStudent ? activeStudent.name : 'NULL_ENTITY'}
        </h1>
        <div className="flex items-center justify-center gap-3">
          <div className="h-[1px] w-12 bg-stone-800"></div>
          <p className="text-stone-500 mono text-[10px] tracking-[0.6em] uppercase">
            Cognitive Phase: {visibleNavItems.find(i => i.id === currentView)?.label || 'Overview'}
          </p>
          <div className="h-[1px] w-12 bg-stone-800"></div>
        </div>
      </div>

      <main key={currentView} className="pb-32 gravity-shift">
        {renderViewContent()}
      </main>

      {activeStudent && (
        <div className="fixed bottom-8 right-8 flex items-center gap-6 z-[100]">
          <button 
            onClick={handleNextView}
            className="liquid-button group relative flex items-center gap-4 bg-white text-stone-950 px-8 py-4 rounded-full font-bold text-xs tracking-[0.2em] uppercase shadow-[0_0_30px_rgba(255,255,255,0.2)] hover:scale-105 transition-all active:scale-95 pointer-events-auto overflow-hidden"
          >
            <span className="relative z-10">Next Phase</span>
            <svg className="w-4 h-4 group-hover:translate-x-1 transition-transform relative z-10" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M14 5l7 7m0 0l-7 7m7-7H3" />
            </svg>
            <div className="absolute inset-0 bg-gradient-to-r from-cyan-400/20 via-magenta-400/20 to-emerald-400/20 opacity-0 group-hover:opacity-100 transition-opacity"></div>
          </button>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Student, AcademicMetrics } from '../../types';
import { predictStudentRisk, PredictionResult } from '../../utils/mlEngine';

