        <TeacherPortal 
          student={activeStudent}
          students={students}
          onSelectStudent={setActiveStudentId}
          onAddStudent={addStudent}
          onDeleteStudent={deleteStudent}
          onUpdateStudent={(updates) => activeStudent && updateStudent(activeStudent.id, updates)}
