              }`}
            >
              {item.label}
              {currentView === item.id && (
                <span className="tab-indicator absolute -bottom-[25px] left-0 w-full h-[2px] bg-gradient-to-r from-cyan-500 to-magenta-500 shadow-[0_0_10px_#00bbf9]"></span>
