      case 'dashboard':
      default:
        return (
          <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-6">
            <div className={`tile rgb-border lg:col-span-4 p-6 flex flex-col h-[500px] ${glowClass}`}>
