  };

  const handleSend = () => {
    if (messageDraft.trim()) {
      onSendMessage(messageDraft.trim());
      setMessageDraft('');
    }
  };

  const updateMetric = (key: keyof AcademicMetrics, value: any) => {
    setFormData(prev => ({
      ...prev,
      academicMetrics: {
        ...prev.academicMetrics,
        [key]: value
