                      </div>
                      <div className="md:col-span-2">
                        <FloatingSelect 
                          label="Primary Subject Sigil"
                          value={formData.subjectEmoji}
                          onChange={(val) => {
                            const selected = SUBJECT_SIGILS.find(s => s.emoji === val);
                            setFormData(prev => ({ 
                              ...prev, 
                              subjectEmoji: val,
                              focusArea: selected ? selected.label : prev.focusArea 
