      >
        {label}
      </label>
    </div>
  );
};

const FloatingSelect = ({ label, value, onChange, options }: { label: string, value: string, onChange: (val: string) => void, options: {label: string, value: string}[] }) => {
  const id = React.useId();
  return (
    <div className="relative group mb-2">
